class GameState:
    def __init__(self):
        self.players: Dict[int, Player] = {}
        self.next_pid = 1
        self.lock = asyncio.Lock()
        self.circle_center = (WORLD_SIZE / 2.0, WORLD_SIZE / 2.0)
        self.circle_radius = WORLD_SIZE / 2.0
        self.phase = "warmup"
