async def broadcaster():
    while True:
        start = time.time()
        async with state.lock:
            state.step(STATE_BROADCAST_EVERY)
            payload = state.full_state()
            writers = list(clients.keys())
        dead = []
        for w in writers:
            try:
                await send_json(w, payload)
            except Exception:
                dead.append(w)
        if dead:
            async with state.lock:
                for w in dead:
                    pid = clients.pop(w, None)
                    if pid is not None:
                        state.remove_player(pid)
        elapsed = time.time() - start
        await asyncio.sleep(max(0.0, STATE_BROADCAST_EVERY - elapsed))

